import{_ as r,o as t,c as s,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"四色蕾丝丝袜","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/四色蕾丝丝袜.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/四色蕾丝丝袜.md"}'),_={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/四色蕾丝丝袜.md"};function d(l,e,i,c,p,h){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"四色蕾丝丝袜",tabindex:"-1"},[n("四色蕾丝丝袜 "),a("a",{class:"header-anchor",href:"#四色蕾丝丝袜","aria-label":'Permalink to "四色蕾丝丝袜"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),o('<h1 id="四色蕾丝丝袜-1" tabindex="-1">四色蕾丝丝袜 <a class="header-anchor" href="#四色蕾丝丝袜-1" aria-label="Permalink to &quot;四色蕾丝丝袜&quot;">​</a></h1><p>四色蕾丝丝袜<br> D+500<br> 这是几条八成新的蕾丝丝袜，因为占库存所以【便宜】卖了，因为丝袜的发明是为了凸显男性的腿型，所以推荐男性购买。<br> 因为库存很多，所以我们支持散货购买，从以下四种丝袜中选择两个给你的左右脚即可，当然，你也可以选择两次购买同样的丝袜，两条腿穿一样的丝袜的确也很协调。<br> 黑丝：黑色丝袜更吸热，也就更易出汗，你使用腿脚进行肉搏攻击时附带1点不可豁免的创伤来源的恶心点数，若你左右脚都是黑丝，则叠加为2点，特殊的，ST可以根据对方的癖好改成等量的亢奋点数。<br> 白丝：白色丝袜略显清纯，让对方对你蕴含的力量进行误判。所以你使用腿脚进行肉搏攻击时获得5【威猛】，若你左右脚都是白丝，则第二条白丝的效果改为，若你具有力量上的附加成功，则腿脚进行的肉搏攻击附带1点不可豁免的创伤来源的疲乏点数，这是被可爱的小脚猛砸胸口的结果。<br> 肉丝：肉色丝袜若隐若现，让被踢的目标陷入你到底穿没穿丝袜的疑惑，这让他的反应略显迟钝，你用腿脚进行的肉搏攻击视为具有D级措手不及，且获得1【高速】。若你的两只脚都是肉丝，则第二条的肉丝改为，若你具有敏捷上的附加成功，则你使用腿脚进行的肉搏攻击附带1点不可豁免的创伤来源的目眩点数，因为敌方会陷入疑惑：“到底穿没穿？刚才踢的是左脚还是右脚？”<br> 红丝：红色丝袜充满诱惑，这让你额外获得等同于风度上附加成功的防御上的闪避加值，若你的左右脚都是红丝，则会发挥完全不一样的效果，不会获得闪避上的防御加值，而是对风度不大于自己的敌方角色进行使用腿脚进行的肉搏攻击时可以不造成伤害，转而造成等量的魅惑点数进行勾引。<br> 此外，在穿着蕾丝丝袜时，你的风度相关检定获得1器械加值。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',4)])])}const f=r(_,[["render",d]]);export{m as __pageData,f as default};
